#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>

#define MG_DIR ".minigit"
#define INDEX_FILE ".minigit/index"
#define COMMITS_DIR ".minigit/commits"
#define MAX_FILES 100
#define MAX_LINE 1024

typedef struct {
    char filename[MAX_LINE];
    char hash[41];
} IndexEntry;

int index_len = 0;
IndexEntry index_entries[MAX_FILES];

void fatal(const char *msg) {
    perror(msg);
    exit(1);
}

void run_cmd(const char *cmd) {
    if (system(cmd) != 0) fatal("system");
}

void init(void) {
    struct stat st;
    if (stat(MG_DIR, &st) == 0) return;
    mkdir(MG_DIR, 0755);
    mkdir(COMMITS_DIR, 0755);
    FILE *f = fopen(INDEX_FILE, "w");
    if (!f) fatal("fopen index");
    fclose(f);
}

void load_index(void) {
    FILE *f = fopen(INDEX_FILE, "r");
    if (!f) fatal("fopen index");
    index_len = 0;
    while (fscanf(f, "%s %s\n",
                  index_entries[index_len].filename,
                  index_entries[index_len].hash) == 2)
        index_len++;
    fclose(f);
}

void save_index(void) {
    FILE *f = fopen(INDEX_FILE, "w");
    if (!f) fatal("fopen index");
    for (int i = 0; i < index_len; i++)
        fprintf(f, "%s %s\n", index_entries[i].filename, index_entries[i].hash);
    fclose(f);
}

void hash_file(const char *path, char *out) {
    sprintf(out, "hashof_%s", path);
}

void cmd_add(int argc, char **argv) {
    if (argc < 1) {
        fprintf(stderr, "usage: minigit add <file>\n");
        exit(1);
    }
    init();
    load_index();
    for (int i = 0; i < argc; i++) {
        struct stat st;
        if (stat(argv[i], &st) < 0) fatal("stat");
        char hash[41];
        hash_file(argv[i], hash);
        int found = 0;
        for (int j = 0; j < index_len; j++)
            if (strcmp(index_entries[j].filename, argv[i]) == 0) {
                strcpy(index_entries[j].hash, hash);
                found = 1;
                break;
            }
        if (!found) {
            strcpy(index_entries[index_len].filename, argv[i]);
            strcpy(index_entries[index_len].hash, hash);
            index_len++;
        }
    }
    save_index();
}

void cmd_commit(int argc, char **argv) {
    if (argc != 1) {
        fprintf(stderr, "usage: minigit commit <message>\n");
        exit(1);
    }
    init();
    load_index();
    char ts[32];
    sprintf(ts, "%ld", (long)time(NULL));
    char commit_path[256];
    sprintf(commit_path, "%s/%s.txt", COMMITS_DIR, ts);
    FILE *f = fopen(commit_path, "w");
    if (!f) fatal("fopen commit");
    fprintf(f, "%s\n", argv[0]);
    for (int i = 0; i < index_len; i++)
        fprintf(f, "%s %s\n", index_entries[i].filename, index_entries[i].hash);
    fclose(f);
    printf("Committed %s\n", ts);
}

void cmd_log(int argc, char **argv) {
    init();
    DIR *d = opendir(COMMITS_DIR);
    if (!d) fatal("opendir");
    struct dirent *ent;
    while ((ent = readdir(d))) {
        if (ent->d_name[0] == '.') continue;
        char path[256];
        sprintf(path, "%s/%s", COMMITS_DIR, ent->d_name);
        FILE *f = fopen(path, "r");
        if (!f) fatal("fopen commit");
        char msg[MAX_LINE];
        if (!fgets(msg, sizeof(msg), f)) continue;
        msg[strcspn(msg, "\n")] = 0;
        printf("%s %s", ent->d_name, msg);
        fclose(f);
    }
    closedir(d);
}

void checkout_commit(const char *ts) {
    char path[256];
    sprintf(path, "%s/%s.txt", COMMITS_DIR, ts);
    FILE *f = fopen(path, "r");
    if (!f) {
        fprintf(stderr, "Commit %s not found\n", ts);
        exit(1);
    }
    char msg[MAX_LINE];
    fgets(msg, sizeof(msg), f);
    index_len = 0;
    while (fscanf(f, "%s %s\n",
                  index_entries[index_len].filename,
                  index_entries[index_len].hash) == 2)
        index_len++;
    fclose(f);
    save_index();
    for (int i = 0; i < index_len; i++) {
        char cmd[1024];
        sprintf(cmd, "cp \"%s.snapshots/%s.%s\" \"%s\" 2>/dev/null || true",
                MG_DIR, index_entries[i].filename, index_entries[i].hash,
                index_entries[i].filename);
        run_cmd(cmd);
    }
}

void cmd_checkout(int argc, char **argv) {
    if (argc != 1) {
        fprintf(stderr, "usage: minigit checkout <timestamp>\n");
        exit(1);
    }
    init();
    load_index();
    checkout_commit(argv[0]);
}

void cmd_reset(int argc, char **argv) {
    if (argc != 1) {
        fprintf(stderr, "usage: minigit reset <timestamp>\n");
        exit(1);
    }
    init();
    load_index();
    checkout_commit(argv[0]);
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command> [args]\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "add") == 0) {
        cmd_add(argc - 2, argv + 2);
    } else if (strcmp(argv[1], "commit") == 0) {
        cmd_commit(argc - 2, argv + 2);
    } else if (strcmp(argv[1], "log") == 0) {
        cmd_log(argc - 2, argv + 2);
    } else if (strcmp(argv[1], "checkout") == 0) {
        cmd_checkout(argc - 2, argv + 2);
    } else if (strcmp(argv[1], "reset") == 0) {
        cmd_reset(argc - 2, argv + 2);
    } else {
        fprintf(stderr, "Unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
